import { useEffect, useState } from "react";
import { PageShell } from "@/components/orderly/PageShell";
import { OdsCheckbox } from "@/components/orderly/OdsCheckbox";
import {
  Info,
  Mail,
  Fingerprint,
  Twitter,
  Chrome,
  Wallet,
  Flame,
  Puzzle,
} from "lucide-react";
import { useTranslation } from "react-i18next";
import { storageKey } from "@/utils/storage";

export default function PrivyConfigPage() {
  const { t } = useTranslation();
  const [privyAppId, setPrivyAppId] = useState("");
  const [privyTermsOfUse, setPrivyTermsOfUse] = useState("");
  const [privyLoginMethods, setPrivyLoginMethods] = useState<string[]>([
    "email",
  ]);
  const [disableEvm, setDisableEvm] = useState(false);
  const [disableSolana, setDisableSolana] = useState(false);
  const [enableAbstract, setEnableAbstract] = useState(false);
  const [toast, setToast] = useState<string | null>(null);

  const isConfigured = privyAppId.trim() !== "";

  const loginMethodOptions = [
    {
      id: "email",
      label: t("privyConfig.methodEmailLabel"),
      description: t("privyConfig.methodEmailDescription"),
      setupRequired: false,
    },
    {
      id: "passkey",
      label: t("privyConfig.methodPasskeyLabel"),
      description: t("privyConfig.methodPasskeyDescription"),
      setupRequired: true,
      setupText: t("privyConfig.methodPasskeySetup"),
    },
    {
      id: "twitter",
      label: t("privyConfig.methodTwitterLabel"),
      description: t("privyConfig.methodTwitterDescription"),
      setupRequired: true,
      setupText: t("privyConfig.methodTwitterSetup"),
    },
    {
      id: "google",
      label: t("privyConfig.methodGoogleLabel"),
      description: t("privyConfig.methodGoogleDescription"),
      setupRequired: true,
      setupText: t("privyConfig.methodGoogleSetup"),
    },
  ];

  useEffect(() => {
    setPrivyAppId(localStorage.getItem(storageKey("orderlyPrivyAppId")) || "");
    setPrivyTermsOfUse(
      localStorage.getItem(storageKey("orderlyPrivyTermsOfUse")) || ""
    );
    const storedMethods = localStorage.getItem(
      storageKey("orderlyPrivyLoginMethods")
    );
    if (storedMethods) {
      try {
        const parsed = JSON.parse(storedMethods) as string[];
        if (parsed.length) setPrivyLoginMethods(parsed);
      } catch {}
    }
    setDisableEvm(
      localStorage.getItem(storageKey("orderlyPrivyDisableEvm")) === "true"
    );
    setDisableSolana(
      localStorage.getItem(storageKey("orderlyPrivyDisableSolana")) === "true"
    );
    setEnableAbstract(
      localStorage.getItem(storageKey("orderlyPrivyEnableAbstract")) === "true"
    );
  }, []);

  useEffect(() => {
    localStorage.setItem(storageKey("orderlyPrivyAppId"), privyAppId);
  }, [privyAppId]);

  useEffect(() => {
    localStorage.setItem(storageKey("orderlyPrivyTermsOfUse"), privyTermsOfUse);
  }, [privyTermsOfUse]);

  useEffect(() => {
    localStorage.setItem(
      storageKey("orderlyPrivyLoginMethods"),
      JSON.stringify(privyLoginMethods)
    );
  }, [privyLoginMethods]);

  useEffect(() => {
    localStorage.setItem(
      storageKey("orderlyPrivyDisableEvm"),
      String(disableEvm)
    );
  }, [disableEvm]);

  useEffect(() => {
    localStorage.setItem(
      storageKey("orderlyPrivyDisableSolana"),
      String(disableSolana)
    );
  }, [disableSolana]);

  useEffect(() => {
    localStorage.setItem(
      storageKey("orderlyPrivyEnableAbstract"),
      String(enableAbstract)
    );
  }, [enableAbstract]);

  function showToast(message: string) {
    setToast(message);
    setTimeout(() => setToast(null), 3000);
  }

  function handleLoginMethodChange(methodId: string, checked: boolean) {
    if (checked) {
      if (!privyLoginMethods.includes(methodId)) {
        setPrivyLoginMethods([...privyLoginMethods, methodId]);
      }
    } else {
      setPrivyLoginMethods(privyLoginMethods.filter(m => m !== methodId));
    }
  }

  function getLoginIcon(id: string) {
    switch (id) {
      case "email":
        return <Mail className="h-4 w-4" />;
      case "passkey":
        return <Fingerprint className="h-4 w-4" />;
      case "twitter":
        return <Twitter className="h-4 w-4" />;
      case "google":
        return <Chrome className="h-4 w-4" />;
      default:
        return null;
    }
  }

  return (
    <PageShell pageTitle={t("privyConfig.pageTitle")}>
      <div className="rounded-xl border border-(--line-subtle) bg-(--bg-surface-primary) p-6">
        <div className="mb-5 flex items-center gap-2">
          <div className="flex h-8 w-8 items-center justify-center rounded-md bg-[rgba(188,135,255,0.12)] text-(--fg-brand)">
            <Wallet className="h-4 w-4" />
          </div>
        </div>

        <div className="mb-5 rounded-lg border border-(--line-subtle) bg-(--bg-surface-secondary) p-4">
          <div className="flex items-start gap-3">
            <Info className="mt-0.5 h-5 w-5 shrink-0 text-(--fg-brand)" />
            <div>
              <p className="mb-1 text-sm font-medium text-(--fg-brand)">
                {t("privyConfig.enhancedWalletOptions")}
              </p>
              <p className="mb-1 text-sm text-(--fg-secondary)">
                <span className="font-medium text-(--fg-brand)">Privy</span>{" "}
                {t("privyConfig.enhancedWalletDescription")}
              </p>
              <ul className="list-disc space-y-0.5 pl-4 text-sm text-(--fg-secondary)">
                <li>{t("privyConfig.featureSocialLogins")}</li>
                <li>{t("privyConfig.featureEmailPhone")}</li>
                <li>{t("privyConfig.featureMultipleWallets")}</li>
                <li>{t("privyConfig.featureEmbeddedWallets")}</li>
              </ul>
            </div>
          </div>
        </div>

        <div className="mb-4">
          <label
            htmlFor="privyAppId"
            className="mb-1.5 block text-sm text-(--fg-secondary)"
          >
            {t("privyConfig.appIdLabel")}
          </label>
          <input
            id="privyAppId"
            type="text"
            value={privyAppId}
            onChange={e => setPrivyAppId(e.target.value)}
            placeholder={t("privyConfig.appIdPlaceholder")}
            className="w-full rounded-lg border border-(--line-subtle) bg-(--bg-input) px-3 py-2 text-sm text-(--fg-primary) outline-none transition-colors focus:border-(--line-brand)"
          />
          <p className="mt-1.5 text-xs text-(--fg-secondary)">
            {t("privyConfig.appIdHelp")}{" "}
            <a
              href="https://dashboard.privy.io"
              target="_blank"
              rel="noopener noreferrer"
              className="font-medium text-(--fg-brand) hover:underline"
            >
              {t("privyConfig.appIdHelpLink")}
            </a>
            {t("privyConfig.appIdHelpSuffix")}
          </p>
        </div>

        <div className="mb-6">
          <label
            htmlFor="privyTermsOfUse"
            className="mb-1.5 block text-sm text-(--fg-secondary)"
          >
            {t("privyConfig.termsOfUseLabel")}{" "}
            <span className="text-(--fg-placeholder)">
              {t("privyConfig.optional")}
            </span>
          </label>
          <input
            id="privyTermsOfUse"
            type="url"
            value={privyTermsOfUse}
            onChange={e => setPrivyTermsOfUse(e.target.value)}
            placeholder={t("privyConfig.termsPlaceholder")}
            className="w-full rounded-lg border border-(--line-subtle) bg-(--bg-input) px-3 py-2 text-sm text-(--fg-primary) outline-none transition-colors focus:border-(--line-brand)"
          />
          <p className="mt-1.5 text-xs text-(--fg-secondary)">
            {t("privyConfig.termsHelp")}
          </p>
        </div>

        <div className="mb-6">
          <h4 className="mb-3 text-base font-medium text-(--fg-primary)">
            {t("privyConfig.loginMethodsTitle")}
          </h4>
          <p className="mb-3 text-xs text-(--fg-secondary)">
            {t("privyConfig.loginMethodsDescription")}
            {!isConfigured && (
              <span className="ml-1 text-orange-400">
                {t("privyConfig.loginMethodsDisabled")}
              </span>
            )}
          </p>
          <div className="space-y-3">
            {loginMethodOptions.map(method => (
              <label
                key={method.id}
                className={`flex items-start gap-3 rounded-lg border border-(--line-subtle) bg-(--bg-surface-secondary) p-3 transition-all ${
                  !isConfigured
                    ? "cursor-not-allowed opacity-50"
                    : "cursor-pointer hover:bg-(--bg-hover)"
                }`}
              >
                <OdsCheckbox
                  checked={privyLoginMethods.includes(method.id)}
                  onCheckedChange={checked =>
                    handleLoginMethodChange(method.id, checked === true)
                  }
                  disabled={!isConfigured}
                  className="mt-1"
                />
                <div className="flex-1">
                  <div
                    className={`flex items-center gap-2 text-sm font-medium ${
                      !isConfigured
                        ? "text-(--fg-placeholder)"
                        : "text-(--fg-primary)"
                    }`}
                  >
                    {getLoginIcon(method.id)}
                    {method.label}
                  </div>
                  <div
                    className={`mt-1 text-xs ${
                      !isConfigured
                        ? "text-(--fg-placeholder)"
                        : "text-(--fg-secondary)"
                    }`}
                  >
                    {method.description}
                  </div>
                  {method.setupRequired && (
                    <div className="mt-1 text-xs text-blue-400">
                      {method.setupText}
                    </div>
                  )}
                </div>
              </label>
            ))}
          </div>
        </div>

        <div className="mb-6">
          <h4 className="mb-3 text-base font-medium text-(--fg-primary)">
            {t("privyConfig.walletConfigurationTitle")}
          </h4>
          <div className="space-y-3">
            <label
              className={`flex items-start gap-3 rounded-lg border border-(--line-subtle) bg-(--bg-surface-secondary) p-3 transition-all ${
                !isConfigured
                  ? "cursor-not-allowed opacity-50"
                  : "cursor-pointer hover:bg-(--bg-hover)"
              }`}
            >
              <OdsCheckbox
                checked={!disableEvm}
                onCheckedChange={checked => setDisableEvm(checked !== true)}
                disabled={!isConfigured}
                className="mt-1"
              />
              <div className="flex-1">
                <div
                  className={`flex items-center gap-2 text-sm font-medium ${
                    !isConfigured
                      ? "text-(--fg-placeholder)"
                      : "text-(--fg-primary)"
                  }`}
                >
                  <Wallet className="h-4 w-4" />
                  {t("privyConfig.enableEvmWallets")}
                </div>
                <div
                  className={`mt-1 text-xs ${
                    !isConfigured
                      ? "text-(--fg-placeholder)"
                      : "text-(--fg-secondary)"
                  }`}
                >
                  {t("privyConfig.evmWalletsDescription")}
                </div>
              </div>
            </label>

            <label
              className={`flex items-start gap-3 rounded-lg border border-(--line-subtle) bg-(--bg-surface-secondary) p-3 transition-all ${
                !isConfigured
                  ? "cursor-not-allowed opacity-50"
                  : "cursor-pointer hover:bg-(--bg-hover)"
              }`}
            >
              <OdsCheckbox
                checked={!disableSolana}
                onCheckedChange={checked => setDisableSolana(checked !== true)}
                disabled={!isConfigured}
                className="mt-1"
              />
              <div className="flex-1">
                <div
                  className={`flex items-center gap-2 text-sm font-medium ${
                    !isConfigured
                      ? "text-(--fg-placeholder)"
                      : "text-(--fg-primary)"
                  }`}
                >
                  <Flame className="h-4 w-4" />
                  {t("privyConfig.enableSolanaWallets")}
                </div>
                <div
                  className={`mt-1 text-xs ${
                    !isConfigured
                      ? "text-(--fg-placeholder)"
                      : "text-(--fg-secondary)"
                  }`}
                >
                  {t("privyConfig.solanaWalletsDescription")}
                </div>
              </div>
            </label>

            <label
              className={`flex items-start gap-3 rounded-lg border border-(--line-subtle) bg-(--bg-surface-secondary) p-3 transition-all ${
                !isConfigured
                  ? "cursor-not-allowed opacity-50"
                  : "cursor-pointer hover:bg-(--bg-hover)"
              }`}
            >
              <OdsCheckbox
                id="enableAbstractWallet"
                checked={enableAbstract}
                onCheckedChange={checked => setEnableAbstract(checked === true)}
                disabled={!isConfigured}
                className="mt-1"
              />
              <div className="flex-1">
                <div
                  className={`flex items-center gap-2 text-sm font-medium ${
                    !isConfigured
                      ? "text-(--fg-placeholder)"
                      : "text-(--fg-primary)"
                  }`}
                >
                  <Puzzle className="h-4 w-4" />
                  {t("privyConfig.enableAbstractWallet")}
                </div>
                <div
                  className={`mt-1 text-xs ${
                    !isConfigured
                      ? "text-(--fg-placeholder)"
                      : "text-(--fg-secondary)"
                  }`}
                >
                  {isConfigured
                    ? t("privyConfig.abstractWalletEnabled")
                    : t("privyConfig.abstractWalletDisabled")}
                </div>
              </div>
            </label>
          </div>
        </div>

        <div className="flex items-center gap-3">
          <button
            type="button"
            onClick={() => showToast(t("privyConfig.configurationSaved"))}
            className="inline-flex items-center gap-2 rounded-full px-5 py-2.5 text-sm font-medium text-(--fg-primary) transition-opacity hover:opacity-90"
            style={{ background: "var(--bg-brand-grad)" }}
          >
            {t("privyConfig.saveConfiguration")}
          </button>
        </div>
      </div>

      {toast && (
        <div className="fixed bottom-5 left-1/2 z-100 -translate-x-1/2 rounded-full border border-(--line-brand) bg-(--bg-surface-primary) px-5 py-2.5 text-sm font-medium text-(--fg-primary) shadow-xl">
          {toast}
        </div>
      )}
    </PageShell>
  );
}
